import{_ as t,c as r,o as p,ae as i}from"./chunks/framework.B7Y1jjX-.js";const v=JSON.parse('{"title":"2.1 JS历史","description":"","frontmatter":{},"headers":[],"relativePath":"notes/前端/三件套/JS/廖雪峰教程/2历史背景/2.1 JS历史.md","filePath":"notes/前端/三件套/JS/廖雪峰教程/2历史背景/2.1 JS历史.md"}'),e={name:"notes/前端/三件套/JS/廖雪峰教程/2历史背景/2.1 JS历史.md"};function c(S,a,o,s,n,J){return p(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="_2-1-js历史" tabindex="-1">2.1 JS历史 <a class="header-anchor" href="#_2-1-js历史" aria-label="Permalink to &quot;2.1 JS历史&quot;">​</a></h1><p>在上个世纪的1995年，当时的网景公司正凭借其Navigator浏览器成为Web时代开启时最著名的第一代互联网公司。</p><p>由于网景公司希望能在静态HTML页面上添加一些动态效果，于是叫Brendan Eich这哥们在两周之内设计出了JavaScript语言。你没看错，这哥们只用了10天时间。</p><p>为什么起名叫JavaScript？原因是当时Java语言非常红火，所以网景公司希望借Java的名气来推广，但事实上JavaScript除了语法上有点像Java，其他部分基本上没啥关系。</p><h3 id="ecmascript" tabindex="-1">ECMAScript <a class="header-anchor" href="#ecmascript" aria-label="Permalink to &quot;ECMAScript&quot;">​</a></h3><p>因为网景开发了JavaScript，一年后微软又模仿JavaScript开发了JScript，为了让JavaScript成为全球标准，几个公司联合ECMA（European Computer Manufacturers Association）组织定制了JavaScript语言的标准，被称为ECMAScript标准。</p><p>所以简单说来就是，ECMAScript是一种语言标准，而JavaScript是网景公司对ECMAScript标准的一种实现。</p><p>那为什么不直接把JavaScript定为标准呢？因为JavaScript是网景的注册商标。</p><p>不过大多数时候，我们还是用JavaScript这个词。如果你遇到ECMAScript这个词，简单把它替换为JavaScript就行了。</p><h3 id="javascript版本" tabindex="-1">JavaScript版本 <a class="header-anchor" href="#javascript版本" aria-label="Permalink to &quot;JavaScript版本&quot;">​</a></h3><p>JavaScript的标准——ECMAScript在不断发展，最新版ECMAScript 6标准（简称ES6）已经在==2015年6月==正式发布了，所以，讲到JavaScript的版本，实际上就是说它实现了ECMAScript标准的哪个版本。</p>',11)])])}const d=t(e,[["render",c]]);export{v as __pageData,d as default};
